import Footer from '@/components/Footer';
import Header from '@/components/Header';

export default function PublicLayout({
  children
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <>
      <Header>
        <h1>Meu Portfólio</h1>
      </Header>
      <main className="mt-32 h-screen bg-background p-8">{children}</main>
      <Footer />
    </>
  );
}
