import { ModeToggle } from '../ModeToggle';

interface HeaderProps {
  children?: React.ReactNode;
}
export default function Header({ children }: HeaderProps) {
  return (
    <header className="fixed top-0 right-0 left-0 z-10 flex items-center justify-around border-b border-b-border bg-background/80 py-4 backdrop-blur-sm">
      {children}
      <ModeToggle />
    </header>
  );
}
